        "question": [
          "Finds the price drift %"
        ],
        "sql": [
          "-- Add DOB/TOB categorization to the price drift analysis\r\n",
          "WITH trade_categorization AS (\r\n",
          "  SELECT DISTINCT\r\n",
          "    b.ExecutionID,\r\n",
          "    b.HedgeServerID,\r\n",
          "    CASE \r\n",
          "      WHEN e.EventPayloadRowData_ExecutionID IS NOT NULL \r\n",
          "        OR b.HedgeServerID IN (35, 81, 82, 83, 84, 85) \r\n",
          "      THEN 'DOB'\r\n",
          "      ELSE 'TOB'\r\n",
          "    END AS TradeCategory\r\n",
          "  FROM main.dealing.bi_output_dealing_bestexecution_report b\r\n",
          "  LEFT JOIN main.dealing.bronze_event_hub_prod_event_streaming_we_oms_pricing_completed_evh e\r\n",
          "    ON CAST(b.ExecutionID AS STRING) = e.EventPayloadRowData_ExecutionID\r\n",
          "    AND LOWER(e.EventPayloadRowData_Orderstate) = 'filled'\r\n",
          "),\r\n",
          "base AS (\r\n",
          "  SELECT\r\n",
          "    b.Date,\r\n",
          "    DATE_FORMAT(b.Date, 'yyyy-MM') AS Month,\r\n",
          "    b.HedgeServerID,\r\n",
          "    b.ExecutionID,\r\n",
          "    ROUND(b.SlippageInDollar, 2) AS RoundedSlippage,\r\n",
          "    b.ActionTypeReason,\r\n",
          "    b.Volume,\r\n",
          "    -- Join OMS Slippage\r\n",
          "    CASE WHEN s.G_Slippage_1USD <= 0 THEN 0 ELSE COALESCE(s.G_Slippage_1USD, 0) END AS OMSSlippageUSD,\r\n",
          "    -- Add trade categorization\r\n",
          "    tc.TradeCategory\r\n",
          "  FROM main.dealing.bi_output_dealing_bestexecution_report b\r\n",
          "  LEFT JOIN main.bi_dealing.bi_output_dealing_slippage s\r\n",
          "    ON b.ExecutionID = s.ExecutionID AND b.PositionID = s.PositionID\r\n",
          "    AND s.PositionID IS NOT NULL\r\n",
          "    AND s.G_IsBuy IS NOT NULL\r\n",
          "    AND s.IsValidCustomerRate = 1\r\n",
          "    AND s.EventPayloadRowData_Orderstate <> 'Rejected'\r\n",
          "  LEFT JOIN trade_categorization tc\r\n",
          "    ON b.ExecutionID = tc.ExecutionID\r\n",
          "  WHERE \r\n",
          "    b.History_Price_Rate IS NOT NULL\r\n",
          "    AND (b.ActionTypeReason IS NOT NULL AND LOWER(b.ActionTypeReason) NOT LIKE '%alignment%')\r\n",
          "    AND b.SlippageInDollar IS NOT NULL\r\n",
          "    AND DATE_FORMAT(b.Date, 'yyyy-MM') IN ('2025-12', '2026-01','2026-02')\r\n",
          "),\r\n",
          "categorized AS (\r\n",
          "  SELECT\r\n",
          "    Month,\r\n",
          "    TradeCategory,\r\n",
          "    CASE\r\n",
          "      WHEN RoundedSlippage = 0 THEN 'No Drift'\r\n",
          "      WHEN RoundedSlippage < 0 THEN 'Positive Drift'\r\n",
          "      ELSE 'Negative Drift'\r\n",
          "    END AS SlippageCategory,\r\n",
          "    RoundedSlippage,\r\n",
          "    OMSSlippageUSD,\r\n",
          "    Volume\r\n",
          "  FROM base\r\n",
          "),\r\n",
          "agg AS (\r\n",
          "  SELECT\r\n",
          "    Month,\r\n",
          "    TradeCategory,\r\n",
          "    SlippageCategory,\r\n",
          "    COUNT(*) AS SlippageCount,\r\n",
          "    ROUND(SUM(RoundedSlippage), 0) AS TotalSlippageUSD,\r\n",
          "    ROUND(SUM(OMSSlippageUSD), 0) AS TotalOMSSlippageUSD,\r\n",
          "    SUM(Volume) AS TotalVolume\r\n",
          "  FROM categorized\r\n",
          "  GROUP BY Month, TradeCategory, SlippageCategory\r\n",
          "),\r\n",
          "month_totals AS (\r\n",
          "  SELECT\r\n",
          "    Month,\r\n",
          "    TradeCategory,\r\n",
          "    SUM(SlippageCount) AS MonthTotalCount\r\n",
          "  FROM agg\r\n",
          "  GROUP BY Month, TradeCategory\r\n",
          ")\r\n",
          "SELECT\r\n",
          "  a.Month,\r\n",
          "  a.TradeCategory,\r\n",
          "  a.SlippageCategory,\r\n",
          "  a.SlippageCount,\r\n",
          "  a.TotalSlippageUSD,\r\n",
          "  a.TotalOMSSlippageUSD,\r\n",
          "  a.TotalVolume,\r\n",
          "  ROUND(100.0 * a.SlippageCount / t.MonthTotalCount, 2) AS SlippageCountPct\r\n",
          "FROM agg a\r\n",
          "JOIN month_totals t \r\n",
          "  ON a.Month = t.Month \r\n",
          "  AND a.TradeCategory = t.TradeCategory\r\n",
          "ORDER BY a.Month DESC, a.TradeCategory, a.SlippageCategory"
        ],
        "usage_guidance": [
          "Understand how the slippage is determined, the rounding and what I am filtering out"
        ]
      },
