          "Find trades with latency"
        ],
        "sql": [
          "WITH base AS (\r\n",
          "  SELECT *\r\n",
          "  FROM main.dealing.bi_output_dealing_bestexecution_report\r\n",
          "  WHERE \r\n",
          "    Date >= '2025-06-01'\r\n",
          "    AND Date < '2026-03-01'\r\n",
          "    AND IsTriggeredPosition = 'NonTriggered'\r\n",
          "    AND ActionTypeReason <> 'Alignment'\r\n",
          "    AND ActionType <> 'Copy'\r\n",
          "),\r\n",
          "table1 AS (\r\n",
          "  SELECT\r\n",
          "    date_trunc('month', Date) AS Month,\r\n",
          "    COUNT(*) AS Trade_Count,\r\n",
          "    SUM(Volume) AS Trade_Volume,\r\n",
          "    COUNT_IF(ClientToExecutionLatency > 1000) AS High_Latency_Trade_Count,\r\n",
          "    SUM(CASE WHEN ClientToExecutionLatency > 1000 THEN Volume ELSE 0 END) AS High_Latency_Trade_Volume,\r\n",
          "    'All' AS TableType\r\n",
          "  FROM base\r\n",
          "  GROUP BY Month\r\n",
          "),\r\n",
          "table2 AS (\r\n",
          "  SELECT\r\n",
          "    date_trunc('month', Date) AS Month,\r\n",
          "    COUNT(*) AS Trade_Count,\r\n",
          "    SUM(Volume) AS Trade_Volume,\r\n",
          "    COUNT_IF(ClientToExecutionLatency > 1000) AS High_Latency_Trade_Count,\r\n",
          "    SUM(CASE WHEN ClientToExecutionLatency > 1000 THEN Volume ELSE 0 END) AS High_Latency_Trade_Volume,\r\n",
          "    'Excl_Nasdaq_5min' AS TableType\r\n",
          "  FROM base\r\n",
          "  WHERE WithinFirst5Minutes_Nasdaq <> 1\r\n",
          "  GROUP BY Month\r\n",
          ")\r\n",
          "SELECT * FROM table1\r\n",
          "UNION ALL\r\n",
          "SELECT * FROM table2\r\n",
          "ORDER BY TableType, Month"
