        "sql": [
          "-- Instrument 28: Bid/Ask per minute (closest to :02s) for 3 liquidity accounts\r\n",
          "-- Period: 27 Feb - 10 Mar 2026\r\n",
          "WITH prices AS (\r\n",
          "  SELECT\r\n",
          "    p.InstrumentID,\r\n",
          "    p.LiquidityAccountID,\r\n",
          "    p.OccurredAtServer,\r\n",
          "    p.Bid,\r\n",
          "    p.Ask,\r\n",
          "    DATE_TRUNC('minute', p.OccurredAtServer) AS minute_bucket,\r\n",
          "    ABS(SECOND(p.OccurredAtServer) - 2) AS dist_from_02,\r\n",
          "    ROW_NUMBER() OVER (\r\n",
          "      PARTITION BY p.LiquidityAccountID, DATE_TRUNC('minute', p.OccurredAtServer)\r\n",
          "      ORDER BY ABS(SECOND(p.OccurredAtServer) - 2), p.OccurredAtServer\r\n",
          "    ) AS rn\r\n",
          "  FROM main.dealing.bronze_pricesfromprovider_marketcurrencyprice p\r\n",
          "  WHERE p.InstrumentID = 28\r\n",
          "    AND p.LiquidityAccountID IN (100018, 305, 330)\r\n",
          "    AND p.etr_ymd >= '2026-02-27'\r\n",
          "    AND p.etr_ymd <= '2026-03-10'\r\n",
          ")\r\n",
          "SELECT\r\n",
          "  InstrumentID,\r\n",
          "  LiquidityAccountID,\r\n",
          "  minute_bucket,\r\n",
          "  OccurredAtServer,\r\n",
          "  Bid,\r\n",
          "  Ask\r\n",
          "FROM prices\r\n",
          "WHERE rn = 1\r\n",
          "ORDER BY LiquidityAccountID, minute_bucket"
